&lt;div class=&quot;question&quot;&gt;
&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;u style=&quot;font-weight: 400; font-size: 21px; display: inline !important;&quot;&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;div class=&quot;section&quot;&gt;
&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Human Rights Day 2025 is being observed globally on 10 December with the theme &amp;ldquo;Our Everyday Essentials&amp;rdquo;.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;

&lt;div class=&quot;section&quot;&gt;
&lt;h3&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/h3&gt;

&lt;ul&gt;
	&lt;li&gt;The day marks the 1948 adoption of the Universal Declaration of Human Rights (UDHR).&lt;/li&gt;
	&lt;li&gt;The 2025 theme &amp;ldquo;Our Everyday Essentials&amp;rdquo; highlights fundamental needs such as safety, food, shelter, expression, and participation.&lt;/li&gt;
	&lt;li&gt;The observance aims to reaffirm universal human rights amid rising global uncertainties.&lt;/li&gt;
	&lt;li&gt;Countries worldwide are holding awareness campaigns, civic engagement activities, and community-led initiatives.&lt;/li&gt;
	&lt;li&gt;The focus is on strengthening human dignity and reinforcing the core values of the UDHR.&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;

&lt;div class=&quot;section&quot;&gt;
&lt;h3&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/h3&gt;

&lt;ul&gt;
	&lt;li&gt;Human Rights Day has been observed annually on December 10 since 1950.&lt;/li&gt;
	&lt;li&gt;The UDHR remains a foundational document guaranteeing universal rights and freedoms.&lt;/li&gt;
	&lt;li&gt;Events often involve governments, civil society, youth groups, and international organisations such as the UN.&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
&lt;/div&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Varanasi.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Prime Minister Narendra Modi inaugurated the 72nd National Volleyball Tournament through video conferencing from Varanasi.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;The 72nd National Volleyball Tournament was inaugurated from Varanasi by Prime Minister Narendra Modi via video conferencing.&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;Teams from 28 states participated in the national-level tournament, reflecting nationwide representation.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;The Prime Minister highlighted values of teamwork, coordination, and shared responsibility through sports.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Varanasi&lt;/span&gt;&lt;/u&gt; &lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;Parliamentary constituency of Prime Minister Narendra Modi&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;Located in Uttar Pradesh&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;Known for its cultural and sporting heritage&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt; &lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;National Volleyball Tournament&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;An annual national-level volleyball championship in India&lt;/li&gt;
		&lt;li&gt;Organized with participation from state teams across the country&lt;/li&gt;
		&lt;li&gt;Serves as a platform for talent identification and promotion of volleyball&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Ek Bharat, Shreshtha Bharat&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;A national initiative aimed at promoting cultural integration&lt;/li&gt;
		&lt;li&gt;Encourages interaction and understanding among Indian states&lt;/li&gt;
		&lt;li&gt;Often highlighted through sports and cultural events&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;One Earth, One Health, One Future.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;The National One Health Mission Assembly 2025 showcased India&amp;rsquo;s integrated approach to health security under the theme &amp;ldquo;One Earth, One Health, One Future.&amp;rdquo;&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;The event is hosted by the Department of Health Research (DHR) under the National One Health Mission.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The &amp;#39;One Health&amp;#39; approach integrates the health of people, animals, and the environment to address complex health challenges.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The mission emphasizes combating zoonotic diseases, antimicrobial resistance, and ensuring food safety.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;It brings together ministries, departments, academicians, and experts, highlighting India&amp;rsquo;s leadership in the One Health approach.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;One Health Approach&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;Addresses health issues by recognizing the interconnectedness of people, animals, and the environment.&lt;/li&gt;
		&lt;li&gt;Crucial for addressing challenges like zoonotic diseases, which can spread from animals to humans.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;National One Health Mission&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Facilitates a unified approach to health security in India.&lt;/li&gt;
		&lt;li&gt;Encourages collaboration across multiple sectors, such as health, agriculture, and environment.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Significance of the Assembly&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Highlights India&amp;rsquo;s growing leadership role in global health security.&lt;/li&gt;
		&lt;li&gt;Demonstrates the importance of integrating different health domains to tackle modern health challenges.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Advancing Internet Governance for an Inclusive and Sustainable Viksit Bharat.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display:flex;gap:6px;align-items:center;&quot;&gt;&lt;img height=&quot;26&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;font-size:21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;The India Internet Governance Forum (IIGF) 2025 will be held on 27&amp;ndash;28 November in New Delhi under the theme &amp;ldquo;Advancing Internet Governance for an Inclusive and Sustainable Viksit Bharat&amp;rdquo;.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display:flex;gap:6px;align-items:center;&quot;&gt;&lt;img height=&quot;26&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;font-size:21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;IIGF 2025 will bring together multi-stakeholder groups &amp;mdash; including government, academia, civil society, and global digital bodies &amp;mdash; to shape India&amp;rsquo;s internet policy ecosystem.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The event will be inaugurated by Union Minister of State for Electronics &amp;amp; IT Shri Jitin Prasada, along with senior officials from MeitY and NIXI.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The forum will host four major panel discussions and twelve workshops across two days, covering digital inclusion, infrastructure, cybersecurity, and AI governance.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The overarching theme aligns with India&amp;rsquo;s long-term vision of Viksit Bharat @2047, focusing on inclusive digital growth and sustainable internet governance.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display:flex;gap:6px;align-items:center;&quot;&gt;&lt;img height=&quot;26&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;font-size:21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;About IIGF&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;Founded in &lt;strong&gt;2021&lt;/strong&gt; as India&amp;rsquo;s national chapter of the &lt;strong&gt;UN Internet Governance Forum (UN IGF)&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;Operates on a &lt;strong&gt;multi-stakeholder model&lt;/strong&gt; ensuring equal representation from all sectors.&lt;/li&gt;
		&lt;li&gt;Managed by a &lt;strong&gt;14-member organising committee&lt;/strong&gt; with diverse expertise.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Key Themes of IIGF 2025&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;Inclusive Digital Future:&lt;/strong&gt; Digital divide, accessibility, rural and marginalised community inclusion.&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Digital Infrastructure for Resilient Growth:&lt;/strong&gt; Cloud systems, data centres, broadband expansion, disaster resilience.&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;AI for People, Planet, and Progress:&lt;/strong&gt; Ethical AI, environmental sustainability, privacy and digital rights.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Event Venues&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;Day 1:&lt;/strong&gt; India Habitat Centre, New Delhi&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Day 2:&lt;/strong&gt; India International Centre, New Delhi&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Participation&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Speakers from &lt;strong&gt;UN IGF, Google Cloud, Meta, CCAOI&lt;/strong&gt;, and premier Indian universities.&lt;/li&gt;
		&lt;li&gt;Focus areas include cybersecurity, AI regulation, internet governance, and digital public goods.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Static Facts&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Event Name: &lt;strong&gt;India Internet Governance Forum (IIGF) 2025&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;Dates: &lt;strong&gt;27&amp;ndash;28 November 2025&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;Organisers: &lt;strong&gt;Ministry of Electronics &amp;amp; IT (MeitY)&lt;/strong&gt; and &lt;strong&gt;NIXI&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;Theme: &lt;strong&gt;Advancing Internet Governance for an Inclusive and Sustainable Viksit Bharat&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;Established: &lt;strong&gt;2021&lt;/strong&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Prof. Vaidyeswaran Rajaraman.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Prof. Vaidyeswaran Rajaraman, a pioneering computer scientist and educator who laid the foundation of computer science education in India, passed away recently.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;He launched India&amp;rsquo;s first &lt;strong&gt;B.Tech programme in Computer Science&lt;/strong&gt; at &lt;strong&gt;IIT Kanpur in 1979&lt;/strong&gt;, shaping the academic foundation of India&amp;rsquo;s IT revolution.&lt;/li&gt;
	&lt;li&gt;His 1968 &lt;strong&gt;Fortran programming booklet&lt;/strong&gt; became a bestseller, initiating generations of Indian programmers into coding.&lt;/li&gt;
	&lt;li&gt;As head of the &lt;strong&gt;Supercomputer Education and Research Centre (IISc, 1982&amp;ndash;1994)&lt;/strong&gt;, he advanced India&amp;#39;s computing capabilities and research.&lt;/li&gt;
	&lt;li&gt;He was honoured with the &lt;strong&gt;Padma Bhushan in 1998&lt;/strong&gt; and the &lt;strong&gt;Shanti Swarup Bhatnagar Prize&lt;/strong&gt; for his contributions to science and technology.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Academic Background&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;Born in Tamil Nadu; studied Physics at &lt;strong&gt;St. Stephen&amp;rsquo;s College&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;Earned an engineering diploma from &lt;strong&gt;IISc Bengaluru&lt;/strong&gt; and a &lt;strong&gt;Ph.D. from the University of Wisconsin&amp;ndash;Madison&lt;/strong&gt;.&lt;/li&gt;
		&lt;li&gt;Received advanced research training at &lt;strong&gt;MIT&lt;/strong&gt; and &lt;strong&gt;Wisconsin&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Professional Contributions&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Established one of India&amp;rsquo;s earliest computer centres with IBM mainframes.&lt;/li&gt;
		&lt;li&gt;Designed the &lt;strong&gt;MCA programme&lt;/strong&gt; to meet growing software industry demands.&lt;/li&gt;
		&lt;li&gt;Trained early programmers who went on to lead firms like &lt;strong&gt;TCS&lt;/strong&gt; and &lt;strong&gt;HCL&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Publications and Legacy&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Authored over &lt;strong&gt;20 textbooks&lt;/strong&gt; on computer science still used across Indian universities.&lt;/li&gt;
		&lt;li&gt;Played a key role in shaping India&amp;rsquo;s software education and bridging academia with industry.&lt;/li&gt;
		&lt;li&gt;Remembered as the &lt;strong&gt;Father of Computer Science Education in India&lt;/strong&gt;.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;AcreRise.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;AcreRise has been named &amp;ldquo;Real Estate Developer of the Year&amp;rdquo; at the Times Business Awards-2026 for its transparency-driven and compliant urban development.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt; &lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;AcreRise received the &amp;ldquo;Real Estate Developer of the Year&amp;rdquo; title at the Times Business Awards-2026.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The company is based in Odisha and plays a key role in Bhubaneswar&amp;rsquo;s infrastructure-led growth.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;AcreRise maintains 100 percent RERA compliance with zero customer complaints.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;AcreRise&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Founded by Sashikant Barik and Sheikh Mairajul Haque&lt;/li&gt;
		&lt;li&gt;Focuses on design-led, legally compliant real estate development&lt;/li&gt;
		&lt;li&gt;Key projects include One World and AcreRise Azure&lt;/li&gt;
	&lt;/ul&gt;
